#include <stdio.h>
#include <string.h>

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        char S1[250001], S2[250001];
        scanf("%s", S1);
        scanf("%s", S2);
        int len1 = strlen(S1), len2 = strlen(S2);
        int maxLen = 0, maxStart = 0;
        for (int i = 0; i < len1; i++) {
            for (int j = 0; j < len2; j++) {
                int k = 0;
                while (i + k < len1 && j + k < len2 && S1[i + k] == S2[j + k]) {
                    k++;
                }
                if (k > maxLen) {
                    maxLen = k;
                    maxStart = i;
                }
            }
        }
        if (maxLen == 0) {
            printf("0\n");
        } else {
            printf("%s\n", S1 + maxStart);
            printf("%d\n", maxLen);
        }
    }
    return 0;
}

