import sys

def solve(S1, S2):
    len1, len2 = len(S1), len(S2)
    maxLen, maxStart = 0, 0
    for i in range(len1):
        for j in range(len2):
            k = 0
            while i + k < len1 and j + k < len2 and S1[i + k] == S2[j + k]:
                k += 1
            if k > maxLen:
                maxLen = k
                maxStart = i
    if maxLen == 0:
        return "0"
    else:
        return S1[maxStart:maxStart + maxLen] + "\n" + str(maxLen)

T = int(sys.stdin.readline())
for _ in range(T):
    S1 = sys.stdin.readline().strip()
    S2 = sys.stdin.readline().strip()
    print(solve(S1, S2))

